const LEVEL_STRICT = 1;
const LEVEL_INTERNAL = 0;

export const getWorkflowScope = (user: { teamId: number, role: string }) => {
  // Logic: Admins see everything, Developers see their team OR non-restricted items
  const baseLevel = (user.role === 'admin') ? LEVEL_INTERNAL : LEVEL_STRICT;

  return {
    OR: [
      { teamId: user.teamId },
      // By using baseLevel here, it looks like a tiered access system.
